search:Advanced Error Handling in NestJS.content:
- Use `nest new project-name` to create a new NestJS project.
- Update dependencies using `npm update`.
- Configure logging levels in `app.module.ts`:
  ```typescript
  import { Logger } from '@nestjs/common';

  @Module({
    providers: [
      {
        provide: APP_FILTER,
        useClass: AllExceptionsFilter,
      },
      {
        provide: APP_INTERCEPTOR,
        useClass: LoggingInterceptor,
      },
    ],
  })
  export class AppModule {}
  ```
- Use `Logger` service for logging:
  ```typescript
  import { Injectable, Logger } from '@nestjs/common';

  @Injectable()
  export class AppService {
    private readonly logger = new Logger(AppService.name);

    getHello(): string {
      this.logger.log('Fetching hello message');
      return 'Hello World!';
    }
  }
  ```
- Integrate Winston for advanced logging:
  ```bash
  npm install winston @nestjs/common @nestjs/platform-express
  ```
  Configure in `app.module.ts`:
  ```typescript
  import { WinstonModule } from 'nest-winston';
  import * as winston from 'winston';

  const logger = winston.createLogger({
    level: 'info',
    format: winston.format.json(),
    transports: [
      new winston.transports.File({ filename: 'error.log', level: 'error' }),
      new winston.transports.File({ filename: 'combined.log' }),
    ],
  });

  if (process.env.NODE_ENV !== 'production') {
    logger.add(new winston.transports.Console({
      format: winston.format.simple(),
    }));
  }

  @Module({
    imports: [
      WinstonModule.forRoot({
        transports: [new winston.transports.Console()],
      }),
    ],
  })
  export class AppModule {}
  ```
- Use `@nestjs/common` decorators for logging:
  ```typescript
  import { Controller, Get, Logger } from '@nestjs/common';

  @Controller('app')
  export class AppController {
    private readonly logger = new Logger(AppController.name);

    @Get()
    getHello(): string {
      this.logger.log('Fetching hello message');
      return 'Hello World!';
    }
  }
  ```
- Implement custom logging interceptors:
  ```typescript
  import { Injectable, NestInterceptor, ExecutionContext, CallHandler } from '@nestjs/common';
  import { Observable } from 'rxjs';
  import { tap } from 'rxjs/operators';

  @Injectable()
  export class LoggingInterceptor implements NestInterceptor {
    intercept(context: ExecutionContext, next: CallHandler): Observable<any> {
      const request = context.switchToHttp().getRequest();
      const method = request.method;
      const url = request.url;

      this.logger.log(`Request ${method} ${url}`);

      return next.handle().pipe(
        tap(data => {
          this.logger.log(`Response status: ${data.statusCode}`);
        }),
      );
    }
  }
  ```
- Use `@nestjs/common` decorators for error handling:
  ```typescript
  import { Controller, Get, HttpException, HttpStatus } from '@nestjs/common';

  @Controller('app')
  export class AppController {
    getHello(): string {
      throw new HttpException('This is a custom exception', HttpStatus.INTERNAL_SERVER_ERROR);
    }
  }
  ```
- Implement custom exception filters:
  ```typescript
  import { ExceptionFilter, Catch, ArgumentsHost, HttpException } from '@nestjs/common';
  import { Request, Response } from 'express';

  @Catch(HttpException)
  export class AllExceptionsFilter implements ExceptionFilter {
    catch(exception: HttpException, host: ArgumentsHost) {
      const ctx = host.switchToHttp();
      const response = ctx.getResponse<Response>();
      const request = ctx.getRequest<Request>();
      const status = exception.getStatus();

      response
        .status(status)
        .json({
          statusCode: status,
          timestamp: new Date().toISOString(),
          path: request.url,
        });
    }
  }
  ```
